<!DOCTYPE html>
<html lang="{{ str_replace('_', '-', app()->getLocale()) }}">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Student Timetable</title><link href="https://fonts.bunny.net/css?family=instrument-sans:400,500,600,700" rel="stylesheet" /><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css"><style>body{font-family:"Instrument Sans",sans-serif;background:linear-gradient(135deg,#020617,#0f172a 54%,#111827 100%);color:#e2e8f0;margin:0;padding:0}.container{max-width:1200px;margin:0 auto;padding:40px 20px}header{display:flex;justify-content:space-between;align-items:center;margin-bottom:40px;border-bottom:1px solid rgba(148,163,184,.1);padding-bottom:20px;gap:12px;flex-wrap:wrap}h1{font-size:2rem;color:#f8fafc;margin:0}.btn{background:linear-gradient(135deg,#22d3ee,#06b6d4);color:#082f49;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-weight:700}.card{background:rgba(15,23,42,.78);border:1px solid rgba(148,163,184,.18);border-radius:16px;padding:24px;margin-bottom:20px}.timetable-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:16px;margin-top:20px}.slot{background:rgba(34,211,238,.1);border:1px solid rgba(34,211,238,.3);padding:16px;border-radius:12px}.slot-time{color:#22d3ee;font-weight:700;font-size:1.1rem}.slot-class{color:#f8fafc;margin-top:8px;font-weight:600}.slot-trainer,.slot-topic{color:#94a3b8;font-size:.9rem;margin-top:4px}.btn-meeting{display:inline-flex;align-items:center;gap:8px;background:#22d3ee;color:#082f49;padding:8px 16px;border-radius:6px;text-decoration:none;font-weight:600;margin-top:12px}</style></head>
<body><div class="container"><header><h1><i class="fa-regular fa-calendar"></i> My Timetable</h1><div style="display:flex;gap:8px;flex-wrap:wrap">@auth<a href="{{ route('dashboard') }}" class="btn" style="background:rgba(34,211,238,.12);color:#22d3ee;border:1px solid rgba(34,211,238,.3)"><i class="fa-solid fa-arrow-left"></i> Back to Dashboard</a>@endauth<form method="POST" action="{{ route('logout') }}">@csrf<button class="btn" type="submit"><i class="fa-solid fa-right-from-bracket"></i> Logout</button></form></div></header><div class="card">@if($timetables->count()>0)<div class="timetable-grid">@foreach($timetables as $slot)<div class="slot"><div class="slot-time">{{ $slot->day_of_week }} • {{ $slot->time_range }}</div><div class="slot-class">{{ $slot->class?->name ?? 'Class unavailable' }}</div><div class="slot-trainer">Trainer: {{ $slot->class?->trainer?->name ?? 'Not assigned' }}</div><div class="slot-topic">{{ $slot->topic ? 'Topic: '.$slot->topic : 'Topic will be shared by your trainer.' }}</div>@if($slot->meeting_link)<a href="{{ $slot->meeting_link }}" target="_blank" class="btn-meeting"><i class="fa-solid fa-video"></i> Join Class</a>@endif</div>@endforeach</div>@else<p style="color:#94a3b8">No timetable available. Please enroll in a class.</p>@endif</div></div></body></html>
